sp_widget.client_script:
api.controller = function($scope, $location) {
    /* widget controller */
    var c = this;

	c.onCancel = function() {
		$scope.$parent.$parent.$dismiss();
	};

	c.onSubmit = function() {
		c.data.submit = true;
		$scope.server.update().then(function(){
			$scope.$parent.$parent.$dismiss();

			// 2.7.0 | 2021-10-22 | mmcc | DFCT0010600 - Deleting the Top Task from Portal App does not redirect to the Tasker Portal Board
			// If on the top task when Delete clicked, navigate to Tasker Portal Board
			if (c.data.parent == '') {
				// STRY0113838
				var url = '/' + $scope.portal.url_suffix;
				if(c.data.templateTaskSysId || c.data.templateSysId){
					url = url + "?id=discovertasker_processtemplatelist&table=x_153465_discovert_discover_routing_template";
				}
				$location.url(url);
			}
		});
	};
};

sp_widget.script:
