// Script Continued Below
//------------------------------------------------------------------------------------------------------------------------
// COMPANY: DISCOVER TECHNOLOGIES
// WIDGET BASE: Tasker Modal - Task Cancellation Comment
//------------------------------------------------------------------------------------------------------------------------
// 2.7.0 | 2021-08-29 | mmcc | STRY0107404 - Draft Scheduled Tasks – UI – Delete Modal 
//											In HTML, Used widget Tasker Modal - Task Cancellation Comment but removed form tags;
//											  moved <footer> to be outside the <div class="modal-body">
//											  to reduce white space at the bottom of the view.
//											In CSS, No CSS here, put in Tasker Theme. 
//											In Service script, all new. Grouped code into functions.
//											In Client controller, all new. Grouped code into functions.
//                                          Changes in HTML, CSS, Server script and Client controller
// 2.7.0 | 2021-09-03 | mmcc | DFCT0010476 - "Acknowledgement Prompt" does not have an "Acknowledge" button so users cannot use Tasker
//											  In HTML, Changed class modal-body to dtech-modal-widget-body; changed footer tag to a div.
//											    Changed class dtech-modal-footer to dtech-modal-widget-footer; dropped class flex.
//                                          Changes in HTML
// 2.7.0 | 2021-09-14 | mmcc | STRY0099532 - DIA- 'Mass Reopen' Task Tree Modal (MVP)
//											   In HTML, changed to generic name usage of delete to submit;
//											     changed CSS Selector .dtech-perm-delete to use .dtech-standard-text-color.
//											   In Sever script, changed deleteButton* to submitButton*.
//											   In Client controller (and HTML), changed deleteTask to onSubmit; changed cancelDeleteTask to onCancel.
//                                          Changes in HTML, Server script and Client controller
// 2.7.0 | 2021-09-26 | raj | DFCT0010541 - When deleting "Draft Scheduled Tasks", it does NOT redirect anywhere.
//                         In Server script, set data.parent object
//                         In client script, redirect to parent or home page
// 2.7.0 | 2021-10-8 | mmcc | STRY0109110 - Draft Scheduled Tasks – UI – Delete Modal- Add Descendant tasks count
//											In HTML, var's msgBody# coded to match AC line #
//											In Service script, Using TaskerHelpers().getDescendantsCount()
//											In Client controller, removed code added from DFCT0010541 as the
//											  Tasker Form with Tabs will handle broadcast and reload
//                                          Changes in HTML, Server script and Client controller
// 2.7.0 | 2021-10-18 | mmcc | STRY0108860 - DIA- Completed from Top Task Notification
//											In Service script, Made params.countType test for 'EXCLUDE_CLOSE'; 
//											 do not count Completed, Closed Incomplete and Cancelled tasks
//                                          Changes in Server script
// 2.7.0 | 2021-10-22 | mmcc | DFCT0010600 - Deleting the Top Task from Portal App does not redirect to the Tasker Portal Board
//											In Client controller, in onSubmit function added redirect if on the Top Task
//                                          Changes in Client controller
//
// 2.7.0 | 2021-11-16 | raj  | STRY0113838 - Tasker Settings- Allow for custom "URL Suffix" for Tasker Portal
//                                         Changes made in Client Script
// 2.7.0 | 2021-11-18 | raj  | STRY0114416 - 4 - 2.7 Certification Fixes
//                                         Changes made in Server Script
// 2.8.0 - 2022-07-09 - raj - STRY0119137 - Stretch- Template UI Clean Up- Delete Top Template Task Confirmation Modal (moved delete to new script)
// 2.8.0 - 2022-07-09 - raj -  STRY0119138 - Stretch- Template UI Clean Up- Delete Template Subtask Confirmation Modal (moved delete to new script)
//
//------------------------------------------------------------------------------------------------------------------------

(function($sp, input, data, options) {
	main();

	function main() {
		if (input) {
			if (input.submit == true) {
				_processInput();
			} else {
				// copy to data[name] from input[name] || option[name]
				_optCopy(['taskSysId', 'taskNumberShortDescription']);
				_optCopy(['templateSysId', 'templateNumberShortDescription']);
				_optCopy(['templateTaskSysId', 'templateTaskNumberShortDescription', 'isTopTemplateTask']);

				_buildMessages();
				_setDataDefaults();
			}
		}
	}

	function _processInput(){
		if(input.taskSysId){
			// run delete step
			// STRY0114416 - 4
			var gr_delete_modal = new GlideRecordSecure('x_153465_discovert_route_task_instance');
			if (gr_delete_modal.get(input.taskSysId)) {
				// DFCT0010541
				data.parent = gr_delete_modal.parent ? gr_delete_modal.getValue('parent') + '' : '';
				new Task_uiAction().uiAction_DeleteTasks(gr_delete_modal);			
			}
		} else if(input.templateTaskSysId){
			var gr_delete_temp_task = new GlideRecordSecure('x_153465_discovert_route_tasks');
			if(gr_delete_temp_task.get(input.templateTaskSysId)){
				data.parent = gr_delete_temp_task.parent ? gr_delete_temp_task.getValue('parent') + '' : '';
				new Template_uiAction().uiAction_DeleteTemplateTask(gr_delete_temp_task);
			}

		} else if(input.templateSysId){
			var gr_delete_temp = new GlideRecordSecure('x_153465_discovert_discover_routing_template');
			if(gr_delete_temp.get(input.templateSysId)){
				new Template_uiAction().uiAction_DeleteTemplate(gr_delete_temp);	
			}
		}
	}
	function _buildMessages() {
		data.cancelButtonText = gs.getMessage('cancel');

		data.submitButtonTitle = gs.getMessage('Delete');
		if(!data.templateTaskSysId && data.templateSysId){
			data.submitButtonText = gs.getMessage('Tasker - Button - Delete Template');
		} else {
			data.submitButtonText = gs.getMessage('Tasker - Button - Delete Task');
		}


		data.msgBody2 = gs.getMessage('Warning');
		var messageShortDescription = "";
		var messageCount = "";
		var count = -1;
		if(data.taskSysId){
			messageShortDescription = data.taskNumberShortDescription;
			count = _getDescendantsCount();
			messageCount = gs.getMessage('Tasker - You are about to permanently delete this task with all its {0} subtasks', [count]);
		} else if(data.templateTaskSysId){
			messageShortDescription = data.templateTaskNumberShortDescription;
			count = _getDescendantsCount();
			if(!data.isTopTemplateTask || data.isTopTemplateTask == 'false'){
				messageCount = gs.getMessage('Tasker - You are about to permanently delete this template task with all its {0} template subtasks', [count]);
			} else {
				messageCount = gs.getMessage('Tasker - This will also delete the entire template with all its {0} template tasks', [count]);
			}
		} else if(data.templateSysId){
			messageShortDescription = data.templateNumberShortDescription;
			count = _getDescendantsCount();
			messageCount = gs.getMessage('Tasker - This will also delete the entire template with all its {0} template tasks', [count]);
		}

		data.msgBody3 = messageShortDescription;
		data.msgBody3_5 = gs.getMessage('Tasker - You are about to permanently delete a Top Template Task');


		data.msgBody4 = messageCount;
		data.msgBody5 = gs.getMessage('Tasker - Are you sure you would like to continue?');

		var messageInfo = "";
		if(data.isTopTemplateTask){
			messageInfo = gs.getMessage('Tasker - You are about to permanently delete a Top Template Task');
		} else {
			messageInfo = gs.getMessage('Tasker - If this task has subtask(s), they will also be deleted');
		}
		data.msgBody6 = messageInfo;
	}

	function _getDescendantsCount() {
		var count = -1;
		var useTempMessage = false;
		var taskTemplateHelpers = new TaskTemplateHelpers();
		var taskerHelpers = new TaskerHelpers();
		if(data.taskSysId){
			// 2.7.0 | 2021-10-18 | mmcc |  STRY0108860 - DIA- Completed from Top Task Notification
			var details = {
				taskSysId: data.taskSysId,
				countType: 'ALL'
			};
			count = taskerHelpers.getDescendantsCount(details);
		} else if(data.templateTaskSysId){
			if(!data.isTopTemplateTask || data.isTopTemplateTask == 'false'){
					count = taskTemplateHelpers.countTemplateTaskSubTasks(data.templateTaskSysId);
			} else {
				useTempMessage = true;
			}
		} else if(data.templateSysId){
				useTempMessage = true;
		}
		// if using template message then, build it
		if(useTempMessage){
			count = taskTemplateHelpers.countAllTemplateTasks(data.templateSysId);
		}

		return count;
	}

	// copy to data from input or options
	function _optCopy(names) {
		names.forEach(function(name) {
			data[name] = input[name] || options[name];
		});
	}

	function _setDataDefaults() {
		data.submit = false;
	}
})($sp, input, data, options);
